            "id": "M1",
            "official": true,
            "version": "1.2.3.4"
          },
          {
            "id": "M2",
            "official": false,
            "version": "1.0.1.23"
          }
        ],
        "right": [
          {
            "id": "M1",
            "official": true,
            "version": "1.2.4.4"
          },
          {
            "id": "M2",
            "official": false,
            "version": "1.0.2.23"
